package actor

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime/actor"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type BootstrapActorProxy struct {
	actor.UnimplementedBootstrapActorServer
	client actor.BootstrapActorClient
}

func init() {
	proxyutil.Register(&actor.BootstrapActor_ServiceDesc, NewBootstrapActorProxy)
}
func NewBootstrapActorProxy(cc grpc.ClientConnInterface) actor.BootstrapActorServer {
	return &BootstrapActorProxy{client: actor.NewBootstrapActorClient(cc)}
}
func (p *BootstrapActorProxy) LoadActor(ctx context.Context, in *runtime.LinkedBundle) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[runtime.LinkedBundle, emptypb.Empty](p.client.LoadActor)(ctx, in)
}
func (p *BootstrapActorProxy) IsResponding(ctx context.Context, in *emptypb.Empty) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[emptypb.Empty, emptypb.Empty](p.client.IsResponding)(ctx, in)
}
